SELECT COUNT(version_id) AS version_count
FROM particle_system_versions
WHERE system_id = 1;

SELECT name, description
FROM particle_systems
WHERE status = 'active';

SELECT asset_type
FROM asset_library
WHERE asset_id = 0;

SELECT COUNT(asset_id) AS total_active_assets
FROM asset_library
WHERE status = 'active' AND uploaded_by = 1;

SELECT name, status, COUNT(system_id) AS total_systems
FROM particle_systems
GROUP BY name, status;

SELECT file_path, asset_type, uploaded_by
FROM asset_library
WHERE status = 'active';
